const { geo, geoFromHeaders, isInRegion, geoDistance } = require('./packages/next/src/server/web/spec-extension/geo.ts');

// Test 1: geo() with Vercel headers
const h1 = new Headers({
  'x-vercel-ip-city': 'San Francisco',
  'x-vercel-ip-country': 'US',
  'x-vercel-ip-country-region': 'CA',
  'x-vercel-ip-latitude': '37.7749',
  'x-vercel-ip-longitude': '-122.4194',
  'x-vercel-ip-timezone': 'America/Los_Angeles',
});
const r1 = geo({ headers: h1 });
console.log('Test 1 - geo():', JSON.stringify(r1));
console.assert(r1.city === 'San Francisco', 'city');
console.assert(r1.countryCode === 'US', 'countryCode');
console.assert(r1.country === 'United States', 'country');

// Test 2: Cloudflare fallback
const h2 = new Headers({ 'cf-ipcountry': 'GB' });
const r2 = geoFromHeaders(h2);
console.log('Test 2 - Cloudflare fallback:', JSON.stringify(r2));
console.assert(r2.countryCode === 'GB', 'cf countryCode');
console.assert(r2.country === 'United Kingdom', 'cf country');

// Test 3: Missing headers
const r3 = geo({ headers: new Headers() });
console.log('Test 3 - empty headers:', JSON.stringify(r3));
console.assert(r3.city === undefined, 'empty city');
console.assert(r3.country === undefined, 'empty country');

// Test 4: isInRegion
console.assert(isInRegion({ countryCode: 'US' }, ['US', 'CA']) === true, 'isInRegion match');
console.assert(isInRegion({ countryCode: 'JP' }, ['US', 'CA']) === false, 'isInRegion no match');
console.assert(isInRegion({ countryCode: 'us' }, ['US']) === true, 'isInRegion case');
console.assert(isInRegion({}, ['US']) === false, 'isInRegion undefined');
console.log('Test 4 - isInRegion: all passed');

// Test 5: geoDistance NY to London
const d = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278');
console.log('Test 5 - NY to London distance:', d, 'km');
console.assert(d > 5520 && d < 5620, 'NY-London ~5570km');

// Test 6: same point = 0
console.assert(geoDistance('0', '0', '0', '0') === 0, 'same point = 0');
console.log('Test 6 - same point: 0');

console.log('All tests passed!');
" 2>&1

